+        "Edit"
+    }
+    fn description(&self) -> &'static str {
+        "Replace exact text in a file"
+    }
+
+    fn parameters(&self) -> serde_json::Value {
+        serde_json::json!({
+            "type": "object",
+            "properties": {
+                "path": {
+                    "type": "string",
+                    "description": "File path to edit"
+                },
