+
+/// Input parameters for the find tool.
+#[derive(Debug, Deserialize)]
+#[serde(rename_all = "camelCase")]
+struct FindInput {
+    pattern: String,
+    path: Option<String>,
+    limit: Option<usize>,
+}
+
+pub struct FindTool {
+    cwd: PathBuf,
+}
+
+impl FindTool {
+    pub fn new(cwd: &Path) -> Self {
+        Self {
+            cwd: cwd.to_path_buf(),
+        }
+    }
+}
+
+#[async_trait]
+impl Tool for FindTool {
+    fn name(&self) -> &'static str {
+        "find"
+    }
+    fn label(&self) -> &'static str {
+        "Find"
+    }
+    fn description(&self) -> &'static str {
+        "Find files by glob pattern"
+    }
+
+    fn parameters(&self) -> serde_json::Value {
+        serde_json::json!({
+            "type": "object",
+            "properties": {
+                "pattern": {
+                    "type": "string",
+                    "description": "Glob pattern to match files (e.g., '**/*.rs', 'src/*.ts')"
+                },
+                "path": {
+                    "type": "string",
+                    "description": "Directory to search (default: current directory)"
+                },
+                "limit": {
+                    "type": "integer",
+                    "description": "Maximum number of results (default: 100)"
+                }
+            },
+            "required": ["pattern"]
+        })
+    }
+
+    async fn execute(
+        &self,
+        _tool_call_id: &str,
+        input: serde_json::Value,
+        _on_update: Option<Box<dyn Fn(ToolUpdate) + Send>>,
+    ) -> Result<ToolOutput> {
+        let input: FindInput =
+            serde_json::from_value(input).map_err(|e| Error::validation(e.to_string()))?;
+
+        let search_path = input
+            .path
+            .as_ref()
+            .map_or_else(|| self.cwd.clone(), |p| resolve_path(p, &self.cwd));
+
+        let limit = input.limit.unwrap_or(100);
+
+        // Build glob pattern
+        let full_pattern = search_path.join(&input.pattern);
+        let pattern_str = full_pattern.to_string_lossy();
+
+        let paths = glob::glob(&pattern_str)
+            .map_err(|e| Error::tool("find", format!("Invalid glob pattern: {e}")))?;
+
+        // Collect and sort by modification time (newest first)
+        let mut entries: Vec<(PathBuf, std::time::SystemTime)> = Vec::new();
+
+        for entry in paths {
+            if entries.len() >= limit * 2 {
+                // Collect extra for sorting
+                break;
+            }
+
+            let Ok(path) = entry else { continue };
+
+            if path.is_dir() {
+                continue;
+            }
+
+            let mtime = path
+                .metadata()
+                .and_then(|m| m.modified())
+                .unwrap_or(std::time::UNIX_EPOCH);
+
+            entries.push((path, mtime));
+        }
+
+        // Sort by modification time (newest first)
+        entries.sort_by_key(|entry| Reverse(entry.1));
+
+        // Take only limit entries
+        let entries: Vec<_> = entries.into_iter().take(limit).collect();
+        let count = entries.len();
+
+        // Format output
+        let output: Vec<String> = entries
+            .iter()
+            .map(|(path, _)| {
+                path.strip_prefix(&self.cwd)
+                    .unwrap_or(path)
+                    .display()
+                    .to_string()
+            })
+            .collect();
+
+        let result = if output.is_empty() {
+            "No files found".to_string()
+        } else {
+            output.join("\n")
+        };
+
+        Ok(ToolOutput {
+            content: vec![ContentBlock::Text(TextContent::new(result))],
+            details: Some(serde_json::json!({
+                "count": count,
+                "limit": limit,
+                "pattern": input.pattern,
+            })),
+        })
+    }
+}
