+// Helper function to extract text content from tool output
+fn get_text_content(content: &[pi::model::ContentBlock]) -> String {
+    content
+        .iter()
+        .filter_map(|block| {
+            if let pi::model::ContentBlock::Text(text) = block {
+                Some(text.text.clone())
+            } else {
+                None
+            }
+        })
+        .collect::<Vec<_>>()
+        .join("\n")
+}
